import type { CSSProperties, PropType, VNode } from "vue";
import { defineComponent, h, nextTick, onMounted, onUnmounted, ref, watch } from "vue";
import { DropTransition } from "vuepress-theme-hope/client";

import "./hitokoto-blog-hero.scss";

interface HitokotoResult {
  id: string;
  hitokoto: string;
  type: "a" | "b" | "c" | "d" | "e" | "f" | "g" | "h" | "i" | "j" | "k" | "l";
  from: string;
  front_who: string;
  creator: string;
  creator_uid: string;
  reviewer: string;
  uid: string;
  commit_from: string;
  created_at: string;
  length: string;
}

export default defineComponent({
  name: "HitokotoBlogHero",

  inheritAttrs: false,

  props: {
    /** Hero text */
    text: {
      type: String,
      required: true,
    },

    /** Hero image */
    image: [String, null],

    /** Hero image dark */
    imageDark: [String, null],

    /** Hero image alt */
    alt: String,

    /** Hero image style */
    imageStyle: [String, Object] as PropType<string | CSSProperties>,
  },

  setup(props) {
    const text = ref("");
    const display = ref("");
    const author = ref("");
    let isMounted = false;

    const getHitokoto = (): Promise<void> =>
      fetch("https://v1.hitokoto.cn")
        .then((res) => res.json() as Promise<HitokotoResult>)
        .then(({ from, hitokoto }) => {
          text.value = hitokoto;
          author.value = from;
        });

    onMounted(() => {
      isMounted = true;

      watch(text, () => {
        display.value = "";
        let index = 0;

        const renderNextWord = async (): Promise<void> => {
          display.value += text.value[index];
          index += 1;

          await nextTick();

          if (index < text.value.length) {
            setTimeout(() => {
              void renderNextWord();
            }, 150);
          } else if (isMounted) {
            setTimeout(() => {
              void getHitokoto();
            }, 3000);
          }
        };

        void renderNextWord();
      });

      void getHitokoto();
    });

    onUnmounted(() => {
      isMounted = false;
    });

    return (): VNode[] => [
      h(DropTransition, { appear: true, group: true, delay: 0.04 }, () => [
        props.image
          ? h("img", {
              key: "light",
              class: ["vp-blog-hero-image", { light: props.imageDark }],
              style: props.imageStyle,
              src: props.image,
              alt: props.alt ?? props.text,
            })
          : null,
        props.imageDark
          ? h("img", {
              key: "dark",
              class: "vp-blog-hero-image dark",
              style: props.imageStyle,
              src: props.imageDark,
              alt: props.alt ?? props.text,
            })
          : null,
      ]),
      h(DropTransition, { appear: true, delay: 0.08 }, () =>
        props.text ? h("h1", { class: "vp-blog-hero-title" }, props.text) : null,
      ),
      h("div", { class: "hitokoto" }, [
        h("p", { class: "hitokoto-text" }, h("span", display.value)),
        h(
          "p",
          {
            class: "hitokoto-author",
            style: { opacity: display.value.length > 4 ? 1 : 0 },
          },
          `——「${author.value}」`,
        ),
      ]),
    ];
  },
});
